/**
 * chinaV3.js — loads backtest results and renders the chinaV3 dashboard panel.
 *
 * Reads results/chinaV3_results.json (generated by backtest/run_chinaV3.py).
 * Called after app.js so nav switching is already wired up.
 */

(function () {
  let cv3Data = null;
  let activeAsset = "NQ";

  // ── load results ────────────────────────────────────────────────────────────
  fetch("results/chinaV3_results.json")
    .then(r => r.json())
    .then(data => {
      cv3Data = data;
      renderSummary();
      renderAsset(activeAsset);
      renderTradeLog(activeAsset);
      drawEquityCurve(activeAsset);
    })
    .catch(() => {
      document.getElementById("cv3Metrics").innerHTML =
        '<p style="color:var(--text-muted);font-size:13px">Run <code>python3 -m backtest.run_chinaV3</code> to generate results.</p>';
    });

  // ── top-level summary (NQ only) ────────────────────────────────────────────
  function renderSummary() {
    const d = cv3Data["NQ"];
    if (!d) return;

    setText("cv3NetPnl", fmt$(d.net_pnl));
    const pnlEl = document.getElementById("cv3NetPnlChange");
    pnlEl.textContent = (d.net_pnl >= 0 ? "+" : "") + fmt$(d.net_pnl) + " from $50,000";
    pnlEl.className = "stat-change " + (d.net_pnl >= 0 ? "positive" : "negative");

    setText("cv3WinRate", d.win_rate + "%");
    setText("cv3Trades", `${d.total_trades} trades`);
    setText("cv3AvgRR", d.avg_rr + "R");
    setText("cv3MaxDD", fmt$(d.max_drawdown));

    const ddEl = document.getElementById("cv3MaxDDPct");
    const phase = d.prop_phase || "eval";
    ddEl.textContent = d.max_drawdown_pct.toFixed(2) + "% — " + phase.toUpperCase();
    ddEl.className = "stat-change " + (phase === "funded" ? "positive" : phase === "failed" ? "negative" : "neutral");
  }

  // ── per-asset metrics card ──────────────────────────────────────────────────
  function renderAsset(asset) {
    activeAsset = asset;
    const d = cv3Data[asset];
    if (!d) return;

    const phase = d.prop_phase || "eval";
    const phaseColor = phase === "funded" ? "pos" : phase === "failed" ? "neg" : "neu";

    const rows = [
      ["Prop Firm Phase",  phase.toUpperCase() + (d.prop_fail_reason ? " ⚠" : ""), phaseColor],
      ["Starting Balance", fmt$(d.starting_balance), "neu"],
      ["Ending Balance",   fmt$(d.ending_balance),   d.ending_balance >= d.starting_balance ? "pos" : "neg"],
      ["Net P&L",         fmt$(d.net_pnl),           d.net_pnl >= 0 ? "pos" : "neg"],
      ["Total Trades",    d.total_trades,             "neu"],
      ["Wins / Losses",   `${d.wins} / ${d.losses}`, "neu"],
      ["Win Rate",        d.win_rate + "%",           d.win_rate >= 50 ? "pos" : "neg"],
      ["Avg R:R",         d.avg_rr + "R",             d.avg_rr >= 2 ? "pos" : "neg"],
      ["Profit Factor",   d.profit_factor,            d.profit_factor >= 1.5 ? "pos" : "neg"],
      ["Max Drawdown",    fmt$(d.max_drawdown) + ` (${d.max_drawdown_pct}%)`, d.max_drawdown_pct < 4 ? "pos" : "neg"],
      ["Daily Loss Limit", "$1,500", "neu"],
      ["Trailing DD Limit","$2,000", "neu"],
      ["Eval Target",      "$3,000", "neu"],
      ["Expectancy/trade", fmt$(d.expectancy), d.expectancy >= 0 ? "pos" : "neg"],
      ["Sharpe Ratio",     d.sharpe_ratio  != null ? d.sharpe_ratio  : "—", d.sharpe_ratio  >= 1 ? "pos" : d.sharpe_ratio  >= 0 ? "neu" : "neg"],
      ["Sortino Ratio",    d.sortino_ratio != null ? d.sortino_ratio : "—", d.sortino_ratio >= 1 ? "pos" : d.sortino_ratio >= 0 ? "neu" : "neg"],
      ["Calmar Ratio",     d.calmar_ratio  != null ? d.calmar_ratio  : "—", d.calmar_ratio  >= 1 ? "pos" : d.calmar_ratio  >= 0 ? "neu" : "neg"],
    ];

    document.getElementById("cv3Metrics").innerHTML = rows.map(([label, val, cls]) => `
      <div class="cv3-row">
        <span class="cv3-row-label">${label}</span>
        <span class="cv3-row-val ${cls}">${val}</span>
      </div>`).join("");

    renderTradeLog(asset);
    drawEquityCurve(asset);
  }

  // ── trade log table ─────────────────────────────────────────────────────────
  function renderTradeLog(asset) {
    const trades = cv3Data[asset]?.trades || [];
    const tbody = document.getElementById("cv3TradeBody");

    tbody.innerHTML = trades.map(t => `
      <tr>
        <td>${t.id}</td>
        <td>${t.asset}</td>
        <td><span class="badge badge-${t.direction}">${t.direction.toUpperCase()}</span></td>
        <td><span class="badge badge-${(t.entry_type||'IDM_POI').toLowerCase().replace('_','-')}">${t.entry_type || 'IDM_POI'}</span></td>
        <td>${fmtTime(t.entry_time)}</td>
        <td>${fmtTime(t.exit_time)}</td>
        <td>${t.entry_price.toFixed(2)}</td>
        <td>${t.exit_price?.toFixed(2) ?? "—"}</td>
        <td>${t.contracts ?? 2}</td>
        <td>${t.stop_pts != null ? t.stop_pts.toFixed(1) + "pts" : "—"}</td>
        <td>${t.rr}R</td>
        <td style="color: ${t.pnl >= 0 ? "var(--positive)" : "var(--negative)"}">${fmt$(t.pnl)}</td>
        <td><span class="badge badge-${t.outcome}">${t.outcome.toUpperCase()}</span></td>
      </tr>`).join("") || `<tr><td colspan="13" style="color:var(--text-muted);text-align:center;padding:20px">No trades</td></tr>`;
  }

  // ── equity curve (canvas) ───────────────────────────────────────────────────
  function drawEquityCurve(asset) {
    const canvas = document.getElementById("cv3EquityCanvas");
    const ctx    = canvas.getContext("2d");
    const curve  = cv3Data[asset]?.equity_curve || [];

    canvas.width  = canvas.offsetWidth  || 400;
    canvas.height = canvas.offsetHeight || 180;

    ctx.clearRect(0, 0, canvas.width, canvas.height);

    if (curve.length === 0) return;

    const start  = 50_000;
    const values = [start, ...curve.map(e => e.equity)];
    const minV   = Math.min(...values) * 0.998;
    const maxV   = Math.max(...values) * 1.002;
    const W = canvas.width, H = canvas.height;
    const pad = { top: 10, right: 16, bottom: 10, left: 16 };

    const xScale = i => pad.left + (i / (values.length - 1)) * (W - pad.left - pad.right);
    const yScale = v => pad.top + (1 - (v - minV) / (maxV - minV)) * (H - pad.top - pad.bottom);

    // Fill under curve
    const grad = ctx.createLinearGradient(0, 0, 0, H);
    grad.addColorStop(0, "rgba(108,99,255,0.25)");
    grad.addColorStop(1, "rgba(108,99,255,0)");

    ctx.beginPath();
    ctx.moveTo(xScale(0), yScale(values[0]));
    values.forEach((v, i) => ctx.lineTo(xScale(i), yScale(v)));
    ctx.lineTo(xScale(values.length - 1), H);
    ctx.lineTo(xScale(0), H);
    ctx.closePath();
    ctx.fillStyle = grad;
    ctx.fill();

    // Line
    ctx.beginPath();
    ctx.moveTo(xScale(0), yScale(values[0]));
    values.forEach((v, i) => ctx.lineTo(xScale(i), yScale(v)));
    ctx.strokeStyle = "var(--accent)";
    ctx.lineWidth = 2;
    ctx.stroke();

    // Dots for each trade
    curve.forEach((e, i) => {
      const x = xScale(i + 1), y = yScale(e.equity);
      ctx.beginPath();
      ctx.arc(x, y, 4, 0, Math.PI * 2);
      ctx.fillStyle = e.outcome === "win" ? "var(--positive)" : "var(--negative)";
      ctx.fill();
    });
  }

  // ── tab switching ───────────────────────────────────────────────────────────
  window.cv3Tab = function (asset, btn) {
    document.querySelectorAll(".tab-group .tab").forEach(b => b.classList.remove("active"));
    btn.classList.add("active");
    if (cv3Data) renderAsset(asset);
  };

  // ── nav integration ──────────────────────────────────────────────────────────
  document.querySelectorAll(".nav-item").forEach(el => {
    el.addEventListener("click", () => {
      const section = el.dataset.section;
      const cv3Panel = document.getElementById("chinaV3Panel");
      const mainStats = document.querySelector(".stats-grid");
      const mainContent = document.querySelector(".content-grid");

      if (section === "chinaV3") {
        cv3Panel.classList.remove("hidden");
        if (mainStats)   mainStats.classList.add("hidden");
        if (mainContent) mainContent.classList.add("hidden");
        // Redraw equity curve (canvas may now be visible/sized)
        if (cv3Data) drawEquityCurve("NQ");
      } else {
        cv3Panel.classList.add("hidden");
        if (mainStats)   mainStats.classList.remove("hidden");
        if (mainContent) mainContent.classList.remove("hidden");
      }
    });
  });

  // ── helpers ─────────────────────────────────────────────────────────────────
  function fmt$(n) {
    return (n < 0 ? "-$" : "$") + Math.abs(n).toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  }

  function fmtTime(iso) {
    if (!iso) return "—";
    const d = new Date(iso);
    return d.toLocaleDateString("en-GB", { day: "2-digit", month: "short" }) + " " +
           d.toLocaleTimeString("en-GB", { hour: "2-digit", minute: "2-digit" });
  }

  function setText(id, val) {
    const el = document.getElementById(id);
    if (el) el.textContent = val;
  }
})();
